 1	import React, { ChangeEvent, Dispatch, FC, MouseEvent, SetStateAction, useState } from 'react';
 2	
 3	import {
 4	  MenuToggle,
 5	  MenuToggleElement,
 6	  Select,
 7	  SelectList,
 8	  SelectOption,
 9	  ToolbarFilter,
10	} from '@patternfly/react-core';
11	import { FilterIcon } from '@patternfly/react-icons';
12	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
13	
14	import './TopologyToolbar.scss';
15	
16	type TopologyToolbarFilterProps = {
17	  selectedNodeFilters: string[];
18	  setSelectedNodeFilters: Dispatch<SetStateAction<string[]>>;
19	  nodeNames: string[];
20	};
21	const TopologyToolbarFilter: FC<TopologyToolbarFilterProps> = ({
22	  nodeNames,
23	  selectedNodeFilters,
24	  setSelectedNodeFilters,
25	}) => {
26	  const { t } = useNMStateTranslation();
27	  const [isNodeFilterExpanded, setIsNodeFilterExpanded] = useState(false);
28	
29	  const onClearAllFilters = () => setSelectedNodeFilters([]);
30	  const onNodeFilterSelect = (event: MouseEvent | ChangeEvent, selection: string) => {
31	    const checked = (event.target as HTMLInputElement).checked;
32	    setSelectedNodeFilters((prevFilters) => {
33	      if (checked) {
34	        return [...prevFilters, selection];
35	      }
36	
37	      return prevFilters.filter((value) => value !== selection);
38	    });
39	  };
40	  return (
41	    <ToolbarFilter
42	      labels={selectedNodeFilters}
43	      deleteLabel={(_, chip) =>
44	        setSelectedNodeFilters(selectedNodeFilters.filter((filter) => filter !== chip))
45	      }
46	      deleteLabelGroup={onClearAllFilters}
47	      categoryName="nodes"
48	    >
49	      <Select
50	        role="menu"
51	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
52	          <MenuToggle
53	            ref={toggleRef}
54	            onClick={() => setIsNodeFilterExpanded(!isNodeFilterExpanded)}
55	            isExpanded={isNodeFilterExpanded}
56	            className="topology-filter__toggle"
57	          >
58	            <FilterIcon className="topology-filter__icon" />
59	            {t('Filter')}
60	          </MenuToggle>
61	        )}
62	        onSelect={onNodeFilterSelect}
63	        selected={selectedNodeFilters}
64	        isOpen={isNodeFilterExpanded}
65	        onOpenChange={(isOpen) => setIsNodeFilterExpanded(isOpen)}
66	      >
67	        <SelectList>
68	          {nodeNames.map((name) => (
69	            <SelectOption
70	              hasCheckbox
71	              key={name}
72	              value={name}
73	              isSelected={selectedNodeFilters.includes(name)}
74	            >
75	              {name}
76	            </SelectOption>
77	          ))}
78	        </SelectList>
79	      </Select>
80	    </ToolbarFilter>
81	  );
82	};
83	
84	export default TopologyToolbarFilter;

